# Algoritmo ElGamal

import random 
import Crypto.Util.number

# Usamos el primo estandar RFC 3526 de 1536 bits MODP
# usamos el primo estandar RFC 3526 de 1536 bit MODP Group
p = int("FFFFFFFFFFFFFFFFC90FDAA22168C234C4C6628B80DC1CD129024E088A67CC74020BBEA6 ",16)

# Usamos el generador estandar de RFC 3526
g = 2

# Generar las llaves privadas
bob = random.getrandbits(256)
alice = random.getrandbits(256)

# Calculamos y
# y = g^bob mod pass
y = pow(g,bob,p)
print("\n y:", y)
print("\n Llave publica de Bob: (p,g,y)", p,g,y)

